/// <summary>
/// New method
/// </summary>
protected void new()
{
    super(classStr(KJP_SM_AutoInvoicePostingIFService),
        methodStr(KJP_SM_AutoInvoicePostingIFService, runFromManualBatchProcess), SysOperationExecutionMode::Synchronous);
}

/// <summary>
/// Default captiion
/// </summary>
/// <returns>Default caption</returns>
public ClassDescription defaultCaption()
{
    return "@KJP:KJP102824";
}

/// <summary>
/// Constructor Class
/// </summary>
/// <param name = "_executionMode">Mode</param>
/// <returns>Instance of class</returns>
public static KJP_SM_AutoInvoicePostingController construct(SysOperationExecutionMode _executionMode = SysOperationExecutionMode::Synchronous)
{
    KJP_SM_AutoInvoicePostingController controller = new KJP_SM_AutoInvoicePostingController();
    controller.parmExecutionMode(_executionMode);
    return controller;
}

/// <summary>
/// main method
/// </summary>
/// <param name = "_args">Args</param>
public static void main(Args _args)
{
    KJP_SM_AutoInvoicePostingController multiThreadingCreateTasksController = KJP_SM_AutoInvoicePostingController::construct();
    multiThreadingCreateTasksController.parmArgs(_args);
    multiThreadingCreateTasksController.startOperation();
}

/// <summary>
/// Must always run in batch
/// </summary>
